import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Limiting the input size to prevent buffer overflow
        int bufferSize = Math.min(input.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copying only up to bufferSize characters from input to buffer
        input.getChars(0, bufferSize, buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
